('Luma AI Genie', 'luma-ai-genie', 'Text-to-3D and NeRF-based 3D capture', 'Luma AI creates photorealistic 3D models from video capture using NeRF technology, and generates 3D assets from text. Used by game developers, architects, and e-commerce for product visualization.', 'https://lumalabs.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 captures/month","Basic quality"]},{"plan":"Pro","price":24.99,"period":"month","features":["25 captures/month","Ultra quality"]}]', 'intermediate', true, '{web,mobile,api}', '{"NeRF 3D capture","Text-to-3D","Video-to-3D","AR export","glTF/USDZ export","Game engine ready","360 capture"}', '{"Unity","Unreal Engine","Blender","iOS","Android"}', 'https://lumalabs.ai/api', true),

('Meshy', 'meshy', 'AI 3D model generation for game developers', 'Meshy generates production-ready 3D models and textures from text or images in minutes. Supports PBR texturing, rigging, and animation, making it ideal for game asset creation and product visualization.', 'https://meshy.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["200 credits/month"]},{"plan":"Pro","price":20,"period":"month","features":["1000 credits/month","Priority GPU"]},{"plan":"Max","price":100,"period":"month","features":["4000 credits/month"]}]', 'intermediate', false, '{web}', '{"Text-to-3D","Image-to-3D","AI texturing","PBR materials","Auto-rigging","FBX/OBJ/GLB export","Batch generation"}', '{"Unity","Blender","Unreal Engine"}', 'https://docs.meshy.ai', true),

('Masterpiece Studio', 'masterpiece-studio', 'AI 3D creation for VR, AR, and games', 'Masterpiece Studio enables creators to design 3D characters and assets using AI assistance in VR or on desktop. Features AI pose generation, character sculpting, and game-ready mesh export.', 'https://masterpiecestudio.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["3 exports/month"]},{"plan":"Pro","price":20,"period":"month","features":["50 exports/month","Commercial license"]}]', 'intermediate', false, '{desktop,web}', '{"VR creation","AI character generation","Sculpting","Rigging","Pose generation","Texture painting","FBX export","Game-ready meshes"}', '{"Unity","Unreal Engine","SteamVR","Oculus"}', 'https://masterpiecestudio.com/learn', true),

('Blockade Labs', 'blockade-labs', 'AI skybox and 360 environment generation', 'Blockade Labs generates immersive 360° skyboxes and panoramic environments from text prompts. Used for game backgrounds, VR environments, and metaverse spaces — export as equirectangular HDR images.', 'https://skybox.blockadelabs.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["50 generations/month"]},{"plan":"Pro","price":9,"period":"month","features":["500 generations/month","Private","HD"]},{"plan":"Studio","price":49,"period":"month","features":["5000 generations/month","API access"]}]', 'beginner', true, '{web,api}', '{"360 skybox generation","Text-to-environment","HDR export","Panoramic images","Custom styles","Remix","Depth maps","VR-ready"}', '{"Unity","Unreal Engine","A-Frame","Three.js"}', 'https://api.blockadelabs.com', true)

