('Boomy', 'boomy', 'Create original songs in seconds with AI', 'Boomy lets anyone create original AI music tracks in seconds by selecting a style. Save, submit to streaming platforms, and earn royalties — over 14 million songs created by the community.', 'https://boomy.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["25 song submissions"]},{"plan":"Personal","price":2.99,"period":"month","features":["Unlimited submissions","Streaming distribution"]},{"plan":"Professional","price":9.99,"period":"month","features":["Advanced editing","Custom samples"]}]', 'beginner', false, '{web,mobile}', '{"AI song creation","Style selection","Streaming distribution","Royalty earning","Song editing","Cover art","Social sharing"}', '{"Spotify","Apple Music","YouTube Music","TikTok"}', 'https://boomy.com', true),

('Aiva', 'aiva', 'AI music composition for film, games, and media', 'AIVA (Artificial Intelligence Virtual Artist) composes emotional soundtracks for film, TV, games, and ads. Upload a reference track or choose from styles, and AIVA generates orchestral and cinematic music.', 'https://aiva.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["3 downloads/month","MP3 only"]},{"plan":"Standard","price":11,"period":"month","features":["15 downloads/month","Commercial license"]},{"plan":"Pro","price":33,"period":"month","features":["300 downloads/month","Full ownership"]}]', 'beginner', false, '{web}', '{"Orchestral composition","Film scoring","Style profiles","Reference track upload","MIDI export","Full ownership option","Cinematic AI"}', '{}', 'https://help.aiva.ai', true),

('Musicfy', 'musicfy', 'AI voice cloning and cover song creation', 'Musicfy lets you create AI covers of any song with famous artist voice models, clone your own voice for music production, and generate original AI music. Popular for creating viral cover tracks.', 'https://musicfy.lol', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 creations/month"]},{"plan":"Pro","price":12.99,"period":"month","features":["Unlimited creations","Commercial license","Voice cloning"]}]', 'beginner', false, '{web}', '{"AI voice cloning","Artist voice models","Song covers","Text-to-song","Stem separation","Voice training","Commercial license"}', '{}', 'https://musicfy.lol', true),

('Beatoven.ai', 'beatoven-ai', 'AI music generation for podcasts and videos', 'Beatoven.ai creates unique, mood-based background music tailored for podcasts, videos, and games. Generates music section by section, matching the emotional arc of your content with royalty-free output.', 'https://beatoven.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["15 min free music/month"]},{"plan":"Pro","price":19,"period":"month","features":["120 min/month","Commercial license"]}]', 'beginner', true, '{web,api}', '{"Mood-based generation","Section editing","Genre selection","Instrument control","Podcast scoring","Royalty-free","API access","WAV/MP3 export"}', '{"Descript","Adobe Premiere","Final Cut"}', 'https://beatoven.ai/docs', true)

