('Bubble', 'bubble', 'No-code app builder with AI integration', 'Bubble is the leading no-code platform for building complex web apps without code. Supports databases, APIs, workflows, and AI plugins. Powers thousands of production SaaS startups.', 'https://bubble.io', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Test apps","bubble.io domain"]},{"plan":"Starter","price":32,"period":"month","features":["Custom domain","25 workflows/month"]},{"plan":"Growth","price":134,"period":"month","features":["Unlimited workflows","Custom plugins"]}]', 'intermediate', false, '{web}', '{"Visual editor","Database","API integrations","Workflows","User auth","AI plugins","Plugins marketplace","Responsive design","PWA"}', '{"Stripe","Twilio","SendGrid","Zapier","OpenAI","Anthropic","Google Maps"}', 'https://manual.bubble.io', true),

('AppGyver', 'appgyver', 'Low-code app builder by SAP for enterprise and citizen devs', 'SAP AppGyver (now SAP Build Apps) is a professional low-code platform for building web and mobile apps with logic, data binding, and enterprise integrations — no coding required.', 'https://www.sap.com/products/technology-platform/low-code.html', 'freemium', '[{"plan":"Community","price":0,"period":"month","features":["Up to 5 users","Basic apps"]},{"plan":"Enterprise","price":0,"period":"month","features":["Custom pricing","Full SAP integration"]}]', 'intermediate', true, '{web,mobile,api}', '{"Drag-and-drop builder","Mobile apps","Data binding","REST/GraphQL","Business logic","SAP integration","PWA","Offline support"}', '{"SAP","REST APIs","Firebase","Supabase"}', 'https://help.sap.com/docs/build-apps', true),

('Glide', 'glide', 'Build apps from spreadsheets and databases with AI', 'Glide turns your Google Sheets, Excel, or Airtable data into beautiful mobile and web apps in minutes. AI features help generate app structure, screen layouts, and automation flows from your data.', 'https://glideapps.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 projects","500 rows","glide.page domain"]},{"plan":"Maker","price":49,"period":"month","features":["Unlimited projects","25000 rows","Custom domain"]}]', 'beginner', true, '{web,mobile,api}', '{"Spreadsheet-to-app","AI app generation","CRUD operations","User roles","Data integrations","Forms","Computed columns","Custom actions"}', '{"Google Sheets","Excel","Airtable","MySQL","BigQuery","SQL Server"}', 'https://docs.glideapps.com', true),

('Adalo', 'adalo', 'No-code mobile and web app builder', 'Adalo lets you build native iOS and Android apps without code using a drag-and-drop interface. Features a database, actions, custom components, and app store publishing built in.', 'https://adalo.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["10 records/collection","adalo.com domain"]},{"plan":"Starter","price":45,"period":"month","features":["Unlimited records","Custom domain","App store"]},{"plan":"Professional","price":65,"period":"month","features":["API access","External collections"]}]', 'beginner', false, '{web,mobile}', '{"Native iOS/Android","Web app","Database","User auth","Push notifications","Custom components","App store publishing","Stripe payments"}', '{"Stripe","Zapier","Airtable","Google Sheets","Xano"}', 'https://help.adalo.com', true),

('Draftbit', 'draftbit', 'Low-code React Native app builder', 'Draftbit is a low-code platform for building React Native apps visually. Generates clean, exportable React Native code, connects to any REST API, and lets developers drop into code when needed.', 'https://draftbit.com', 'freemium', '[{"plan":"Starter","price":19,"period":"month","features":["3 apps","50 components"]},{"plan":"Pro","price":79,"period":"month","features":["Unlimited apps","Code export","Custom fonts"]}]', 'intermediate', false, '{web}', '{"Visual React Native builder","Code export","REST API connection","Custom components","Navigation","Authentication","Data tables","Responsive preview"}', '{"Firebase","Supabase","Airtable","Xano","REST APIs"}', 'https://docs.draftbit.com', true),

('FlutterFlow', 'flutterflow', 'Build Flutter apps visually with AI assistance', 'FlutterFlow is a visual development platform for building native mobile apps and web apps using Flutter. AI can generate entire app layouts, suggest database structures, and write Dart code snippets.', 'https://flutterflow.io', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["1 project","View mode only"]},{"plan":"Standard","price":30,"period":"month","features":["Code export","Custom domain","Unlimited projects"]},{"plan":"Pro","price":70,"period":"month","features":["GitHub sync","Custom code","Teams"]}]', 'intermediate', false, '{web}', '{"Flutter/Dart","Visual app builder","AI generation","Firebase integration","Custom code","GitHub sync","Responsive","Code export","Custom actions"}', '{"Firebase","Supabase","Stripe","RevenueCat","OpenAI","Google Maps"}', 'https://docs.flutterflow.io', true)

