('Heuritech', 'heuritech', 'AI trend forecasting for fashion brands', 'Heuritech analyzes millions of social media images daily using computer vision to identify emerging fashion trends 12-18 months in advance. Used by luxury brands to optimize product development and buying.', 'https://heuritech.com', 'paid', '[{"plan":"Enterprise","price":0,"period":"month","features":["Custom pricing","Full trend platform"]}]', 'intermediate', false, '{web}', '{"Trend forecasting","Social image analysis","Micro-trend detection","Demand signals","Seasonal planning","Category analysis","Competitive tracking","Sustainability scoring"}', '{"SAP","PLM systems"}', 'https://heuritech.com', true),

('Stitch Fix Hybrid Design', 'stitch-fix-ai', 'AI-human hybrid styling and personalization', 'Stitch Fix uses AI algorithms to match customers with clothing based on style, fit, budget, and feedback. The AI handles initial curation while human stylists refine selections, creating a hybrid model.', 'https://stitchfix.com', 'paid', '[{"plan":"Standard","price":20,"period":"month","features":["Styling fee applied to purchase","Personal stylist","AI curation"]}]', 'beginner', false, '{web,mobile}', '{"AI style curation","Personal stylist","Style quiz","Outfit recommendations","Fit feedback","Size model","Keep what you like","Direct buy"}', '{}', 'https://stitchfix.com', true)

