INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('Be My Eyes', 'be-my-eyes', 'AI visual assistance for blind and low-vision users', 'Be My Eyes connects blind and low-vision people with sighted volunteers and a GPT-4V AI assistant. The AI (Be My AI) can describe images, read documents, navigate websites, and answer visual questions instantly.', 'https://bemyeyes.com', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Free for users","AI assistant included"]}]', 'beginner', false, '{mobile,web}', '{"AI image description","Document reading","Product identification","Navigation help","Scene description","Label reading","Real-time volunteer connection","24/7 AI"}', '{}', 'https://bemyeyes.com', true),

('Speechify', 'speechify', 'AI text-to-speech for reading accessibility', 'Speechify converts any text — web pages, PDFs, docs, emails — into natural-sounding audio. Popular with people with dyslexia, ADHD, and visual impairments, as well as busy professionals who prefer audio.', 'https://speechify.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Basic voices","1x speed"]},{"plan":"Premium","price":139,"period":"year","features":["AI voices","4.5x speed","AI summaries","Offline mode"]}]', 'beginner', false, '{web,mobile,desktop}', '{"Text-to-speech","AI voices","OCR scanning","Speed control","AI summaries","Highlights","Offline","Chrome extension","Word highlighting"}', '{"Google Drive","Dropbox","Google Docs","Notion","Chrome"}', 'https://speechify.com/blog', true),

('UserWay', 'userway', 'AI-powered web accessibility widget', 'UserWay provides an AI accessibility widget that makes websites comply with WCAG, ADA, and other standards. Auto-remediates accessibility violations, adds keyboard navigation, and provides an accessibility menu for users.', 'https://userway.org', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["Accessibility widget","Basic compliance"]},{"plan":"Professional","price":49,"period":"month","features":["Advanced AI","Manual audit","VPAT"]},{"plan":"Enterprise","price":0,"period":"month","features":["Custom pricing","SLA","CDN"]}]', 'beginner', true, '{web,api}', '{"WCAG compliance","AI auto-remediation","Accessibility menu","Screen reader support","Keyboard navigation","Color contrast fix","Font adjustments","Audit reports"}', '{"WordPress","Shopify","Wix","Squarespace","Webflow"}', 'https://userway.org/developers', true),

('Otter.ai (Accessibility)', 'otter-ai-accessibility', 'Real-time captions and transcription for meetings', 'Otter.ai provides live transcription for meetings, lectures, and events in real time, making conversations accessible to deaf and hard-of-hearing users. AI generates summaries, action items, and searchable transcripts.', 'https://otter.ai', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["300 min/month transcription","3 imports"]},{"plan":"Pro","price":17,"period":"month","features":["1200 min/month","Custom vocab","Summary actions"]}]', 'beginner', false, '{web,mobile}', '{"Real-time transcription","Live captions","AI summaries","Action items","Speaker ID","Custom vocabulary","Zoom integration","Searchable archive"}', '{"Zoom","Google Meet","Microsoft Teams","Webex","Dropbox","Salesforce"}', 'https://help.otter.ai', true)

