INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published) VALUES

('Semantic Scholar', 'semantic-scholar', 'AI-powered academic research engine', 'Semantic Scholar is a free AI-powered academic search engine from the Allen Institute for AI. Features semantic search, citation graphs, TLDR summaries of papers, and research recommendations.', 'https://semanticscholar.org', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Full access","API","No account required"]}]', 'intermediate', true, '{web,api}', '{"Semantic paper search","TLDR summaries","Citation graphs","Research recommendations","Author profiles","Topic feeds","Literature review","API access"}', '{}', 'https://api.semanticscholar.org', true),

('ResearchRabbit', 'researchrabbit', 'AI tool for literature discovery and mapping', 'ResearchRabbit is called the "Spotify for papers" — it builds interactive citation networks, discovers related papers, and creates visual research maps. Free for all researchers.', 'https://researchrabbitapp.com', 'free', '[{"plan":"Free","price":0,"period":"month","features":["Full access","Unlimited papers","Team collections"]}]', 'intermediate', false, '{web}', '{"Citation network visualization","Paper discovery","Research maps","Similar work finder","Author tracking","Email alerts","Zotero sync","Team sharing"}', '{"Zotero","Semantic Scholar","PubMed"}', 'https://help.researchrabbitapp.com', true),

('Litmaps', 'litmaps', 'Visual literature mapping for researchers', 'Litmaps creates dynamic visual maps of academic literature showing how papers are connected through citations over time. Helps researchers discover gaps, key papers, and track field evolution.', 'https://litmaps.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["5 maps","20 seed articles"]},{"plan":"Individual","price":10,"period":"month","features":["Unlimited maps","Unlimited seeds","Alerts"]}]', 'intermediate', false, '{web}', '{"Citation maps","Literature discovery","Timeline view","Alert system","Collaboration","Export to reference managers","Gap analysis"}', '{"Zotero","Mendeley","Endnote","CSV export"}', 'https://app.litmaps.com', true),

('SciSpace', 'scispace', 'AI copilot for reading and understanding research papers', 'SciSpace (formerly Typeset) lets you chat with research papers, get plain-language explanations of complex concepts, extract data, and discover related literature. Covers 200M+ papers.', 'https://scispace.com', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["30 paper reads/month","5 questions/paper"]},{"plan":"Premium","price":12,"period":"month","features":["Unlimited reads","Unlimited questions","Export"]}]', 'beginner', true, '{web,api}', '{"Chat with papers","Plain language explanations","Data extraction","Literature discovery","Citation finder","Research notes","Chrome extension","API"}', '{}', 'https://help.scispace.com', true),

('Consensus', 'consensus', 'AI search engine for scientific research', 'Consensus searches across 200M+ research papers and uses AI to surface consensus findings on any question. Shows percentage of studies that agree, key claims, and evidence quality without paywalls.', 'https://consensus.app', 'freemium', '[{"plan":"Free","price":0,"period":"month","features":["20 searches/day","Basic extractions"]},{"plan":"Premium","price":10.99,"period":"month","features":["Unlimited searches","GPT-4 summaries","Filters"]}]', 'beginner', false, '{web}', '{"Scientific consensus search","Evidence synthesis","Study quality meter","Claim extraction","Related papers","AI study summary","Filter by year/design"}', '{}', 'https://consensus.app', true)

